-- 하롱베이 5성급 풀빌라 리조트 / 바이짜이 해변 / 86개 독립 빌라
-- ============================================================================
-- 실행 순서: 020-hotel-schema-rebuild.sql 이후 실행
-- ※ 시즌:
--   - 로우시즌 상반기: 2026/01/01 ~ 2026/05/30
--   - 하이시즌:       2026/05/31 ~ 2026/08/16
--   - 로우시즌 하반기: 2026/08/17 ~ 2026/12/31
-- ※ 요일: 평일(일~목) / 주말(금·토)
-- ※ 금액: 빌라 1동 기준 / 조식포함 / 저녁식사 미포함
-- ※ 베트남 국가 공휴일 추가차지 900,000동/인 의무:
--    노동절(04/30~05/03, 2박 필수), 독립기념일(08/30~09/02, 2박 필수),
--    연말새해(12/31~01/01, 1박 필수)
-- ============================================================================
-- 아동 요금:
--   - 1세~5세: 무료
--   - 6~11세 엑스트라 미사용: 700,000동
--   - 6~11세 엑스트라 사용: 1,250,000동
--   - 성인 엑스트라베드: 1,400,000동
-- ============================================================================

BEGIN;

-- ============================================================================
-- 1. hotel_info INSERT
-- ============================================================================

INSERT INTO hotel_info (
  hotel_code, hotel_name, product_type, location,
  star_rating, check_in_time, check_out_time,
  phone, currency, notes, active
) VALUES (
  'OAKWOOD_HALONG',
  '오크우드 하롱 빌리지',
  'VILLA_RESORT',
  '하롱베이 바이짜이',
  5,
  '14:00:00',
  '12:00:00',
  NULL,
  'VND',
  '5성급 풀빌라 리조트 / 바이짜이 해변 앞 86개 독립 빌라 / 레스토랑+스파+컨퍼런스룸+수영장 / 1층 전용마당+주방(인덕션,냉장고,전자레인지,세탁기)+거실 / 프리미어 빌라: 단독 프라이빗 수영장 보유 / 아동요금: 1~5세 무료, 6~11세 엑스트라 미사용 700,000동, 사용 1,250,000동 / 성인 엑스트라베드 1,400,000동 / 국가공휴일 추가차지 900,000동/인 의무(노동절 2박필수, 독립기념일 2박필수, 연말 1박필수)',
  TRUE
)
ON CONFLICT (hotel_code) DO UPDATE SET
  hotel_name     = EXCLUDED.hotel_name,
  location       = EXCLUDED.location,
  star_rating    = EXCLUDED.star_rating,
  notes          = EXCLUDED.notes,
  updated_at     = NOW();

-- ============================================================================
-- 2. hotel_price INSERT
-- 빌라 4종 × 베드수 × 시즌3 × 요일2 = 총 78행
-- hotel_price_code: OAKWOOD_HALONG_{빌라코드}_{N}BED_{시즌}_{요일}
--   빌라코드: DLXGARDEN(디럭스가든), JRGARDEN(주니어가든), DLXLAKE(디럭스레이크), FAMILY(패밀리코너)
--   시즌: LOW_H1(로우상반기) / HIGH(하이) / LOW_H2(로우하반기)
--   요일: WD(평일) / WE(주말)
-- ============================================================================

INSERT INTO hotel_price (
  hotel_price_code, hotel_code, hotel_name,
  room_type, room_name, room_category, occupancy_max, include_breakfast,
  base_price, extra_person_price, child_policy,
